  "options": [
    {
      "text": "इटररेटर से रनटाइम ओवरहेड",
      "hint": "Rust इटररेटर शून्य-लागत अभिव्यक्तियाँ हैं"
    },
    {
      "text": "कच्चे लूप के समान प्रदर्शन"
    },
    {
      "text": "धीमा लेकिन अधिक पठनीय",
      "hint": "अभिव्यक्ति रनटाइम प्रदर्शन को प्रभावित नहीं करती"
    },
    {
      "text": "ऑप्टिमाइज़ेशन स्तर पर निर्भर करता है",
      "hint": "अभिव्यक्ति संकलन समय पर हटा दी जाती है"
    }
  ],
  "questionProse": [
    "इन दो कार्यान्वयनों के प्रदर्शन की तुलना कैसे होती है?"
  ],
  "explanationProse": [
    "Rust की शून्य-लागत अभिव्यक्तियाँ समान कुशल कोड में संकलित होती हैं:",
    "मुख्य सिद्धांत:\n      1. जो आप उपयोग नहीं करते, उसके लिए आप भुगतान नहीं करते\n      2. जो आप उपयोग करते हैं, उसे आप बेहतर हाथ से नहीं लिख सकते\n\n      सर्वश्रेष्ठ प्रथाएँ:\n      1. उच्च-स्तरीय अभिव्यक्तियों का स्वतंत्र रूप से उपयोग करें\n      2. कंपाइलर के अनुकूलन पर भरोसा रखें\n      3. अनुकूलन से पहले प्रोफ़ाइल करें\n      4. पहले पठनीयता पर ध्यान दें\n      5. इटररेटर और क्लोज़र का बिना डर उपयोग करें"
  ]
}
